VALUES
  ('bookkeeper-moex-01162', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '已充任記帳士者，依民國105年11月9日最新修正公布之記帳士法，下列何者構成撤銷或廢止其記帳士 證書之法定情事？', '["經公立醫院證明有精神病者", "因殺人罪而判刑確定者", "受破產之宣告尚未復權者", "受本法所定除名處分者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01163', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法第13條，下列何者非記帳士在登錄區域內所得執行之業務？', '["受委任辦理停業、復業登記", "受委任辦理稅捐稽徵案件之申報", "受委任辦理稅捐之訴願", "受委任辦理商業會計事務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01164', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '記帳士法規定，記帳士登錄後，非加入記帳士公會，不得執行業務。關於公會之相關規定，下列何者正確？', '["記帳士申請加入記帳士公會時，公會享有裁量權，即便具有會員資格者，亦得拒絕其加入", "一行政區域內開業記帳士未滿30人者，只能選擇加入鄰近區域之記帳士公會，不得聯合組織之", "各級記帳士公會理事、監事任期均為4年", "在人口較多的區域內，得報經主管機關核准，增設第二個同級之記帳士公會，以服務社會大眾"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01165', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '甲記帳士受申誡處分 3 次，依法應另受停止執行業務之處分。此時，對甲記帳士所為之停止執行業務處 分，最低之期間為何？', '["1個月以上", "2個月以上", "3個月以上", "5個月以上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01166', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '記帳士應付懲戒者，由記帳士懲戒委員會處理之。依「記帳士懲戒委員會與懲戒覆審委員會組織及審議 規則」之規定，記帳士懲戒委員會置委員9人，其中，記帳士代表應有幾人？', '["未規定應有記帳士代表", "1人", "2人", "3人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01167', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，記帳士有死亡、撤銷、廢止或自行申請註銷資格或其他不得執業之情形，應向那一個 機關辦理註銷登錄？', '["經濟部", "財政部所屬各地國稅局", "各稅捐稽徵處", "各縣市政府"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01168', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，記帳士受委任人委任後，如須與委任人終止契約，應於幾天前通知委任人，在未得委 任人同意前，不得終止進行？', '["5天", "10天", "15天", "20天"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01169', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，李君曾任臺南地方稅務機關稅務人員，自離職之日起幾年後，始可在臺南市區域內登 錄執行記帳士業務？', '["1年", "2年", "3年", "4年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01170', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，下列何者非記帳士應付懲戒之情事？', '["記帳士黃君因酒醉開車撞傷路人，被檢察官依過失傷人起訴，並判刑半年確定", "記帳士黃君自己逃漏稅捐，經稅捐機關處分在案者", "記帳士黃君幫助委託人逃漏稅捐，經移送法辦者", "記帳士黃君違反記帳士公會章程之規定，情節重大者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01171', 'bookkeeper', 'bookkeeper-moex-105-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '依記帳士法規定，下列有關記帳士交付懲戒之敘述，何者錯誤？', '["記帳士有應付懲戒情事時，利害關係人、業務事件主管機關或記帳士公會得列舉事實，提出證據，報 請主管機關交付懲戒", "被懲戒人對於記帳士懲戒委員會之決議不服者，得於決議書送達之翌日起10日內，向記帳士懲戒覆審 委員會請求覆審", "記帳士懲戒委員會應將交付懲戒事件，通知被付懲戒人，並命其於通知送達之翌日起20日內，提出答 辯或到會陳述；未依限提出答辯或到會陳述時，得逕行決議", "記帳士懲戒委員會處理懲戒事件，認為有犯罪嫌疑者，應即移送司法機關偵辦"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "bd3eaadefb1c", "answer_pdf_sha1": "9b2da7a32888", "source_family": "moex-gov-tw", "moex": {"exam_code": "105170", "c": "602", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "105", "exam_name": "105年建築師技師第二次食品技師不動產經紀人記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
